/**
 * Help Page — Getting started, FAQs, platform disclosure.
 */
import { useNavigate } from 'react-router-dom';
import usePageTitle from '../hooks/usePageTitle';
import s from './HelpPage.module.css';

const FAQS = [
  { q: 'What is Aura Alpha?', a: 'An AI-powered quant research platform that discovers, validates, and ranks trading strategies. It is a research-only tool — it does not trade, allocate capital, or manage money.' },
  { q: 'Does it trade for me?', a: 'No. Aura Alpha is strictly a research and recommendation platform. You review strategies and make your own decisions. There is no automated trading or capital management.' },
  { q: 'How do strategies get validated?', a: 'Every strategy passes walk-forward testing across multiple out-of-sample windows and is scored for regime stability (bull, bear, sideways, high-volatility, low-volatility).' },
  { q: 'What is the Alpha Score?', a: 'A composite quality score combining Sharpe ratio, profit factor, drawdown, win rate, regime stability, and walk-forward performance. Higher = more robust.' },
  { q: 'Can I cancel anytime?', a: 'Yes. All plans can be canceled at any time with no commitment. You retain access until the end of your billing period.' },
  { q: 'What plan should I start with?', a: 'Explorer is free and lets you browse the strategy economy. Most serious traders choose Pro for full validation metrics and AI insights.' },
];

export default function HelpPage() {
  usePageTitle('Help');
  const nav = useNavigate();
  return (
    <div className={s.page}>
      <div className={s.container}>
        <h1 className={s.title}>Help Center</h1>
        <p className={s.subtitle}>Getting started, common questions, and platform disclosure.</p>

        <div className={s.quickStart}>
          <div className={s.quickStartLabel}>Quick Start</div>
          <div className={s.quickStartBody}>
            1. Browse the <span className={s.inlineLink} onClick={() => nav('/economy')}>Strategy Economy</span> to see top-ranked strategies.<br />
            2. Click any strategy to see its validation metrics and "Why This Stands Out" panel.<br />
            3. Open the <span className={s.inlineLink} onClick={() => nav('/quant-desk')}>Quant Desk</span> for your daily research review.<br />
            4. Follow, bookmark, or add strategies to your watchlist for tracking.
          </div>
        </div>

        <h2 className={s.faqHeading}>FAQ</h2>
        {FAQS.map(faq => (
          <div key={faq.q} className={s.faqCard}>
            <div className={s.faqQuestion}>{faq.q}</div>
            <div className={s.faqAnswer}>{faq.a}</div>
          </div>
        ))}

        <div className={s.footer}>
          <span className={s.footerText}>
            Need more help? <span className={s.inlineLink} onClick={() => nav('/contact')}>Contact support</span>
          </span>
        </div>
      </div>
    </div>
  );
}
